INSERT INTO `v1_028bd840a5ccc48eea257169c4584255215e333d1d4ec0a65ff64b00cf199e54` VALUES (1, 2, 1, 1, "", 1, "", "---", 0, "アヤネ");
INSERT INTO `v1_028bd840a5ccc48eea257169c4584255215e333d1d4ec0a65ff64b00cf199e54` VALUES (0, 1, 2, 1, "", 3, "逆境に屈することなく、部員たちを引っ張る主将。ミート力を活かした安定感のある打撃が持ち味。", "---", 6000, "アサヒ");
INSERT INTO `v1_028bd840a5ccc48eea257169c4584255215e333d1d4ec0a65ff64b00cf199e54` VALUES (3, 3, 3, 1, "ホームランを連発すると、連発数に応じてパワーアップする", 0, "無愛想だが仲間を大切に想う気持ちは誰よりも強い男。ケンカで鍛えた腕っぷしが自慢のパワーヒッター。", "アドレナリン", 16000, "部員3");
INSERT INTO `v1_028bd840a5ccc48eea257169c4584255215e333d1d4ec0a65ff64b00cf199e54` VALUES (2, 2, 4, 1, "幸運のハプニングを呼び込む", 2, "みんなからの厚い信頼を集める期待の助っ人部員。実力は未知数だが幸運なハプニングを呼び込む。", "ラッキー", 30000, "{0}");
INSERT INTO `v1_028bd840a5ccc48eea257169c4584255215e333d1d4ec0a65ff64b00cf199e54` VALUES (1, 0, 5, 0, "", 1, "みんなの知らない極秘情報がのっているおまけページ。決して誰かに見せてはいけない。", "", 50000, "選手名鑑 おまけページ");
